import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Document, Page } from 'react-pdf';
import './App.css';

function App() {
  const [selectedPdf, setSelectedPdf] = useState(null);
  const [pdfs, setPdfs] = useState([]);
  const [watsonResponses, setWatsonResponses] = useState({
    summary: '',
    recommendations: '',
    actions: '',
    insights: ''
  });
  const [chatInput, setChatInput] = useState('');
  const [numPages, setNumPages] = useState(null);
  const [pageNumber, setPageNumber] = useState(1);

  // Fetch available PDFs from backend
  useEffect(() => {
    const fetchPdfs = async () => {
      try {
        const response = await axios.get('http://localhost:8000/pdfs');
        setPdfs(response.data);
      } catch (error) {
        console.error('Error fetching PDFs:', error);
      }
    };
    fetchPdfs();
  }, []);

  // Fetch Watson analysis when PDF is selected
  useEffect(() => {
    const fetchWatsonAnalysis = async () => {
      if (selectedPdf) {
        try {
          const response = await axios.post('http://localhost:8000/analyze', { 
            pdf: selectedPdf 
          });
          setWatsonResponses(response.data);
        } catch (error) {
          console.error('Error fetching Watson analysis:', error);
        }
      }
    };
    fetchWatsonAnalysis();
  }, [selectedPdf]);

  const handlePdfSelect = (pdf) => {
    setSelectedPdf(pdf);
  };

  const handleChatSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:8000/chat', { 
        message: chatInput,
        context: watsonResponses
      });
      setChatInput('');
    } catch (error) {
      console.error('Error sending chat message:', error);
    }
  };

  const onDocumentLoadSuccess = ({ numPages }) => {
    setNumPages(numPages);
  };

  return (
    <div className="app-container">
      <div className="left-panel">
        <div className="watson-sections">
          {Object.entries(watsonResponses).map(([key, value]) => (
            <div key={key} className="watson-section">
              <h3>{key.charAt(0).toUpperCase() + key.slice(1)}</h3>
              <p>{value || `No ${key} available`}</p>
            </div>
          ))}
        </div>
        <div className="chat-box">
          <form onSubmit={handleChatSubmit}>
            <input 
              type="text"
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              placeholder="Type your message..."
            />
            <button type="submit">Send</button>
          </form>
        </div>
      </div>
      <div className="right-panel">
        <select 
          onChange={(e) => handlePdfSelect(e.target.value)}
          value={selectedPdf || ''}
        >
          <option value="">Select a PDF</option>
          {pdfs.map((pdf, index) => (
            <option key={index} value={pdf}>{pdf}</option>
          ))}
        </select>

        {selectedPdf && (
          <div className="pdf-viewer">
            <Document
              file={`http://localhost:8000/pdf/${selectedPdf}`}
              onLoadSuccess={onDocumentLoadSuccess}
            >
              <Page pageNumber={pageNumber} />
            </Document>
            <p>Page {pageNumber} of {numPages}</p>
            {pageNumber > 1 && (
              <button onClick={() => setPageNumber(pageNumber - 1)}>
                Previous Page
              </button>
            )}
            {pageNumber < numPages && (
              <button onClick={() => setPageNumber(pageNumber + 1)}>
                Next Page
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
